// file: client/src/store/roleStore.ts

/**
 * useRoleStore - Zustand store for custom agent roles with persistence.
 * Manages role CRUD, import/export, and localStorage sync.
 *
 * @status active
 * @phase 96
 * @depends zustand, zustand/middleware (persist), immer
 * @used_by RoleEditor, MentionPopup
 */

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { produce } from 'immer';

// MARKER_102_2_START
export interface CustomRole {
  id: string;
  name: string; // "@architect"
  displayName: string; // "Senior Architect"
  systemPrompt: string; // Full system message
  capabilities: string[]; // ["code", "design"]
  preferredModel?: string;
  createdAt: Date;
  updatedAt: Date;
}

// Ensure titan_core preset is available
const DEFAULT_ROLES: Omit<CustomRole, 'id' | 'createdAt' | 'updatedAt'>[] = [
  {
    name: '@titan',
    displayName: 'Titan Core',
    systemPrompt: 'You are Titan Core, a powerful reasoning engine designed for complex problem-solving and deep analysis. You excel at breaking down intricate challenges, identifying patterns, and providing well-reasoned solutions. Your approach is methodical and thorough, ensuring no detail is overlooked.',
    capabilities: ['reasoning', 'analysis', 'problem-solving'],
    preferredModel: 'titan_core'
  }
];
// MARKER_102_2_END

interface RoleStore {
  roles: CustomRole[];
  addRole: (role: Omit<CustomRole, 'id' | 'createdAt' | 'updatedAt'>) => void;
  updateRole: (id: string, updates: Partial<CustomRole>) => void;
  deleteRole: (id: string) => void;
  exportRole: (id: string) => void;
  importRole: (json: string) => void;
  getRoleById: (id: string) => CustomRole | undefined;
}

export const useRoleStore = create<RoleStore>()(
  persist(
    (set, get) => ({
      roles: [],

      addRole: (roleData) => {
        const newRole: CustomRole = {
          ...roleData,
          id: `role-${crypto.randomUUID()}`,
          createdAt: new Date(),
          updatedAt: new Date(),
        };

        set(
          produce((state) => {
            state.roles.push(newRole);
          })
        );

        // Sync to backend (async, non-blocking)
        fetch('/api/roles', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(newRole),
        }).catch(console.error);
      },

      updateRole: (id, updates) => {
        set(
          produce((state) => {
            const role = state.roles.find((r: CustomRole) => r.id === id);
            if (role) {
              Object.assign(role, updates, { updatedAt: new Date() });
            }
          })
        );
      },

      deleteRole: (id) => {
        set(
          produce((state) => {
            state.roles = state.roles.filter((r: CustomRole) => r.id !== id);
          })
        );
      },

      exportRole: (id) => {
        const role = get().roles.find((r) => r.id === id);
        if (!role) return;

        const blob = new Blob([JSON.stringify(role, null, 2)], {
          type: 'application/json',
        });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `${role.name}.vetka-role.json`;
        a.click();
        URL.revokeObjectURL(url);
      },

      importRole: (json) => {
        try {
          const parsed = JSON.parse(json);
          if (!parsed.name || !parsed.systemPrompt) {
            throw new Error('Invalid role format');
          }
          get().addRole(parsed);
        } catch (err) {
          console.error('Import failed:', err);
        }
      },

      getRoleById: (id) => {
        const state = get();
        return state.roles.find((r) => r.id === id);
      },
    }),
    {
      name: 'vetka-custom-roles',
      version: 1,
      // Add default roles on first initialization
      onRehydrateStorage: () => {
        return (state, error) => {
          if (error) {
            console.error('Role store hydration error:', error);
            return;
          }

          // Add default roles if store is empty
          if (state && state.roles.length === 0) {
            DEFAULT_ROLES.forEach(role => {
              state.addRole(role);
            });
          }
        };
      }
    }
  )
);
