```python
# file: src/api/chat_manager.py

import json
import os
from typing import Dict, List
from datetime import datetime

class ChatManager:
    def __init__(self, chat_history_file: str = "chat_history.json"):
        self.chat_history_file = chat_history_file
        self.chats = self._load_chats()

    def _load_chats(self) -> Dict:
        """Load chats from JSON file"""
        if os.path.exists(self.chat_history_file):
            with open(self.chat_history_file, 'r') as f:
                return json.load(f)
        return {}

    def _save_chats(self):
        """Save chats to JSON file"""
        with open(self.chat_history_file, 'w') as f:
            json.dump(self.chats, f, indent=2)

    # MARKER_FAVORITE_START
    def toggle_favorite(self, chat_id: str) -> bool:
        """
        Toggle favorite state for a chat and persist to storage.
        Returns the new favorite state.
        """
        if chat_id not in self.chats:
            raise ValueError(f"Chat {chat_id} not found")

        # Toggle the favorite state
        current_state = self.chats[chat_id].get('is_favorited', False)
        new_state = not current_state
        self.chats[chat_id]['is_favorited'] = new_state

        # Update last modified timestamp
        self.chats[chat_id]['last_modified'] = datetime.now().isoformat()

        # Persist to file
        self._save_chats()

        return new_state
    # MARKER_FAVORITE_END

    def get_chats_sorted(self) -> List[Dict]:
        """
        Get all chats sorted by favorite status (favorited first) 
        and then by last_message_at timestamp (newest first)
        """
        chats_list = list(self.chats.values())

        # Sort by favorite status first, then by timestamp
        chats_list.sort(
            key=lambda x: (
                not x.get('is_favorited', False),  # False sorts before True, so negate
                -datetime.fromisoformat(x.get('last_message_at', x.get('created_at', '1970-01-01T00:00:00'))).timestamp()
            )
        )

        return chats_list
