import json
from typing import Dict, List, Any
from datetime import datetime

class Engram:
    def __init__(self, preferences_file: str = "user_preferences.json"):
        self.preferences_file = preferences_file
        self.preferences = self._load_preferences()

    def _load_preferences(self) -> Dict:
        """Load user preferences from JSON file"""
        if os.path.exists(self.preferences_file):
            with open(self.preferences_file, 'r') as f:
                return json.load(f)
        return {}

    def _save_preferences(self):
        """Save user preferences to JSON file"""
        with open(self.preferences_file, 'w') as f:
            json.dump(self.preferences, f, indent=2)

    # MARKER_PREFERENCE_START
    def store_user_preference(self, category: str, key: str, value: Any):
        """
        Store a user preference in the specified category.

        Args:
            category: The preference category (e.g., 'chat_preferences')
            key: The preference key (e.g., 'favorited_chats')
            value: The preference value (e.g., list of chat IDs)
        """
        if category not in self.preferences:
            self.preferences[category] = {}

        self.preferences[category][key] = value
        self.preferences[category]['last_updated'] = datetime.now().isoformat()

        self._save_preferences()

    def get_user_preference(self, category: str, key: str, default=None):
        """
        Retrieve a user preference from the specified category.

        Args:
            category: The preference category
            key: The preference key
            default: Default value if preference not found

        Returns:
            The preference value or default
        """
        return self.preferences.get(category, {}).get(key, default)
    # MARKER_PREFERENCE_END
