// file: client/src/hooks/useApiErrorMonitor.ts

import { useEffect } from 'react';
import { useStore } from '../store/useStore';

/**
 * Hook to monitor API calls and report errors to the store
 * Captures failed fetch requests and displays them in the UI
 */
export const useApiErrorMonitor = () => {
  const setError = useStore((state) => state.setError);

  useEffect(() => {
    // Store original fetch function
    const originalFetch = window.fetch;

    // Override fetch to intercept requests
    window.fetch = async function (...args) {
      try {
        const response = await originalFetch(...args);

        // Check if response is not ok (4xx, 5xx errors)
        if (!response.ok) {
          const errorText = await response.text();
          const errorMessage = `API Error: ${response.status} ${response.statusText} - ${errorText}`;
          setError(errorMessage);
          console.error(`[API Monitor] ${errorMessage}`);
        }

        return response;
      } catch (error) {
        // Network errors or other exceptions
        const errorMessage = `Network Error: ${error.message}`;
        setError(errorMessage);
        console.error(`[API Monitor] ${errorMessage}`);
        throw error;
      }
    } as typeof window.fetch;

    // Cleanup: restore original fetch
    return () => {
      window.fetch = originalFetch;
    };
  }, [setError]);
};
```

This implementation creates a hook that monitors all fetch requests made by the application. It intercepts API calls and checks for HTTP errors (4xx, 5xx status codes) as well as network errors. When an error is detected, it reports it to the global store using the `setError` action, which will display the error in the UI.

The hook should be used in the main App component to ensure it captures all API calls throughout the application lifecycle. It preserves the original fetch functionality while adding error monitoring capabilities.

